package ua.university.sms.model.entity;
import jakarta.persistence.*;import jakarta.validation.constraints.*;import java.util.*;
@Entity public class Student{@Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id;@NotBlank @Size(min=3,max=200) private String fullName;@Email @NotBlank @Column(unique=true) private String email;@Min(1)@Max(6) private int year;@Enumerated(EnumType.STRING) private StudentStatus status=StudentStatus.ACTIVE;@OneToMany(mappedBy="student",cascade=CascadeType.REMOVE) private List<Enrollment> enrollments=new ArrayList<>(); public Long getId(){return id;}public void setId(Long id){this.id=id;}public String getFullName(){return fullName;}public void setFullName(String fullName){this.fullName=fullName;}public String getEmail(){return email;}public void setEmail(String email){this.email=email;}public int getYear(){return year;}public void setYear(int year){this.year=year;}public StudentStatus getStatus(){return status;}public void setStatus(StudentStatus status){this.status=status;}public List<Enrollment> getEnrollments(){return enrollments;}}
